/// Quality module configuration
///
/// Use the builder pattern to configure and register this module:
///
/// ```text
/// let quality = QualityModule::builder()
///     .with_database(pool.clone())
///     .build()?;
///
/// // Unguarded full CRUD (trusted/admin); compose a guarded router for production.
/// let router = quality.all_crud_routes();
/// ```
pub struct QualityModule {
    pub non_conformance_service: Arc<NonConformanceService>,
    pub quality_action_service: Arc<QualityActionService>,
    pub quality_inspection_service: Arc<QualityInspectionService>,
    pub quality_inspection_reading_service: Arc<QualityInspectionReadingService>,
    pub quality_inspection_template_service: Arc<QualityInspectionTemplateService>,
    pub quality_inspection_parameter_service: Arc<QualityInspectionParameterService>,
    pub quality_procedure_service: Arc<QualityProcedureService>,
}

impl QualityModule {
    /// Create a new module builder
    pub fn builder() -> QualityModuleBuilder {
        QualityModuleBuilder::new()
    }

    /// Mount ALL generated CRUD endpoints (12 per entity) with NO domain
    /// validation — the fully **unguarded** surface. A well-formed request can
    /// create invalid rows or soft-delete a referenced master out from under its
    /// dependents. Prefer a guarded composition (read + validated writes) for any
    /// real deployment; use this only in trusted/admin/seeding contexts.
    pub fn all_crud_routes(&self) -> Router {
        use presentation::http::{
            create_non_conformance_routes,
            create_quality_action_routes,
            create_quality_inspection_routes,
            create_quality_inspection_reading_routes,
            create_quality_inspection_template_routes,
            create_quality_inspection_parameter_routes,
            create_quality_procedure_routes,
        };

        Router::new()
            .merge(create_non_conformance_routes(self.non_conformance_service.clone()))
            .merge(create_quality_action_routes(self.quality_action_service.clone()))
            .merge(create_quality_inspection_routes(self.quality_inspection_service.clone()))
            .merge(create_quality_inspection_reading_routes(self.quality_inspection_reading_service.clone()))
            .merge(create_quality_inspection_template_routes(self.quality_inspection_template_service.clone()))
            .merge(create_quality_inspection_parameter_routes(self.quality_inspection_parameter_service.clone()))
            .merge(create_quality_procedure_routes(self.quality_procedure_service.clone()))
    }

    /// Deprecated alias for [`Self::all_crud_routes`]. `routes()` reads like
    /// "the routes" but mounts UNVALIDATED generic CRUD on every entity — a naive
    /// mount exposes unguarded writes. Compose a guarded router (read + validated
    /// writes) for production, or call `all_crud_routes()` to opt into the full
    /// unguarded surface explicitly.
    #[deprecated(note = "mounts unvalidated generic CRUD on every entity; compose a guarded router for production, or call all_crud_routes() for the intentional full/unguarded surface")]
    pub fn routes(&self) -> Router {
        self.all_crud_routes()
    }
}

